/**
 * Findings — Unified finding management centre.
 *
 * System design:
 *   • Every finding gets a stable external_id (AL-YYYY-NNNNN) generated by
 *     the backend on first insert and never changed.
 *   • All state mutations go to PATCH /api/v1/soc/findings/{id} which writes
 *     to the findings table and inserts a row into finding_activity for audit.
 *   • Bulk mutations go to POST /api/v1/soc/bulk.
 *   • localStorage mirrors last-known state for optimistic UI; cleared on
 *     every successful server sync.
 *   • Indexes: external_id (unique), severity, status, category, agent_id,
 *     sla_status, assignee, composite_score DESC, first_detected_at DESC.
 *
 * Case workflow:
 *   NEW → TRIAGING → INVESTIGATING → IN_REMEDIATION → CLOSED
 *                                                   → FALSE_POSITIVE
 *                                                   → ACCEPTED_RISK
 *                                                   → DUPLICATE
 *   Any closed state → REOPENED → back to TRIAGING
 */
import { useState, useEffect, useCallback, useRef } from "react";
import {
  AlertTriangle, RefreshCw, CheckCircle2, XCircle, Shield,
  Clock, ChevronDown, ChevronRight, Filter, Search,
  MessageSquare, Activity, Copy, ExternalLink, Zap,
  User, Calendar, Tag, ArrowRight, RotateCcw, Hash,
  TrendingUp, FileText, GitBranch, Radio, Send,
  CheckSquare, Square, AlertCircle, Layers,
} from "lucide-react";
import { cn } from "../../lib/utils";
import { useRBAC } from "../context/RBACContext";
import { fmtTs, type DetectionFinding } from "./DetectionShared";

const SOC = "/api/v1/soc";

// ── Types ─────────────────────────────────────────────────────────────────────

interface Finding extends DetectionFinding {
  status:          string;
  priority?:       number;
  assignee?:       string;
  analyst_notes?:  string;
  sla_due?:        number;
  sla_status?:     string;
  closed_at?:      number;
  external_id?:    string;
  display_id?:     string;
  tags?:           string | string[];
}

interface ActivityEntry {
  action:    string;
  actor:     string;
  created_at:number;
  old_value: string;
  new_value: string;
  comment?:  string;
}

// ── System Design — Status & Category Config ──────────────────────────────────

const STATUS_FLOW: { key: string; label: string; badge: string; next: string[] }[] = [
  { key: "new",            label: "New",            badge: "bg-red-50 text-red-700 border-red-300",      next: ["triaging","false_positive","duplicate"] },
  { key: "triaging",       label: "Triaging",       badge: "bg-amber-50 text-amber-700 border-amber-300",next: ["investigating","false_positive","accepted_risk","duplicate"] },
  { key: "investigating",  label: "Investigating",   badge: "bg-blue-50 text-blue-700 border-blue-300",   next: ["in_remediation","false_positive","accepted_risk","duplicate"] },
  { key: "in_remediation", label: "In Remediation", badge: "bg-purple-50 text-purple-700 border-purple-300", next: ["closed","false_positive"] },
  { key: "closed",         label: "Closed",         badge: "bg-green-50 text-green-700 border-green-300", next: ["new"] },
  { key: "false_positive", label: "False Positive", badge: "bg-gray-100 text-gray-500 border-gray-300",   next: ["new"] },
  { key: "accepted_risk",  label: "Accepted Risk",  badge: "bg-amber-50 text-amber-600 border-amber-300", next: ["new"] },
  { key: "duplicate",      label: "Duplicate",      badge: "bg-gray-100 text-gray-400 border-gray-200",   next: ["new"] },
];

const STATUS_MAP = Object.fromEntries(STATUS_FLOW.map(s => [s.key, s]));

const WORKFLOW_STEPS = ["new","triaging","investigating","in_remediation","closed"];

