// ── Helpers ───────────────────────────────────────────────────────────────────

function relTime(ts: number): string {
  if (!ts) return "—";
  const s = Math.floor(Date.now() / 1000 - ts);
  if (s < 60)    return `${s}s ago`;
  if (s < 3600)  return `${Math.floor(s / 60)}m ago`;
  if (s < 86400) return `${Math.floor(s / 3600)}h ago`;
  return `${Math.floor(s / 86400)}d ago`;
}

function catKey(cat: string): string {
  const c = cat.toLowerCase();
  if (c.includes("exec") || c.includes("malware") || c.includes("script")) return "execution";
  if (c.includes("network") || c.includes("connection") || c.includes("c2") || c.startsWith("feed")) return "network";
  if (c.includes("package") || c.includes("vuln") || c.includes("cve")) return "package";
  if (c.includes("persist") || c.includes("service") || c.includes("task") || c.includes("config")) return "persistence";
  if (c.includes("user") || c.includes("identity") || c.includes("account")) return "user";
  if (c.includes("security") || c.includes("posture") || c.includes("sip") || c.includes("firewall")) return "security";
  return c;
}

function catCfg(cat: string) { return CAT_CONFIG[catKey(cat)] ?? { label: cat, color: "text-gray-600", dot: "bg-gray-400", bg: "bg-gray-100 border-gray-200" }; }

function useCountUp(target: number): number {
  const [val, setVal] = useState(0);
  const ref = useRef(0);
  useEffect(() => {
    const diff = target - ref.current; const steps = 20; let i = 0;
    const t = setInterval(() => { i++; setVal(Math.round(ref.current + diff * (1 - Math.pow(1 - i/steps, 3)))); if (i >= steps) { clearInterval(t); ref.current = target; } }, 30);
    return () => clearInterval(t);
  }, [target]);
  return val;
}

function parseArr(v: unknown): string[] {
  if (Array.isArray(v)) return v as string[];
  if (typeof v === "string" && v.startsWith("[")) { try { return JSON.parse(v); } catch {} }
  return [];
}

// ── API ───────────────────────────────────────────────────────────────────────

async function patchFinding(id: number, body: Record<string, unknown>): Promise<boolean> {
  try { const r = await fetch(`${SOC}/findings/${id}`, { method: "PATCH", headers: { "Content-Type": "application/json" }, body: JSON.stringify(body) }); return r.ok; }
  catch { return false; }
}

async function bulkAction(ids: number[], action: string, value?: string): Promise<boolean> {
  try { const r = await fetch(`${SOC}/bulk`, { method: "POST", headers: { "Content-Type": "application/json" }, body: JSON.stringify({ finding_ids: ids, action, value, actor: "analyst" }) }); return r.ok; }
  catch { return false; }
}

// ── KPI tile ──────────────────────────────────────────────────────────────────

function KpiTile({ label, value, sub, color, bg, icon, delay }: {
  label: string; value: number; sub?: string;
  color: string; bg: string; icon: React.ReactNode; delay?: number;
}) {
  const count = useCountUp(value);
  return (
    <div className={cn("rounded-xl border p-3 text-center al-bounce-in", bg)} style={{ animationDelay: `${delay ?? 0}ms` }}>
      <div className="flex justify-center mb-1 opacity-60">{icon}</div>
      <div className={cn("text-xl font-black tabular-nums leading-none", color)}>{count}</div>
      <div className="text-[9px] text-gray-500 font-semibold mt-1">{label}</div>
      {sub && <div className="text-[8px] text-gray-400 mt-0.5">{sub}</div>}
    </div>
  );
}

// ── Status workflow strip ─────────────────────────────────────────────────────

function WorkflowStrip({ current }: { current: string }) {
  const idx = WORKFLOW_STEPS.indexOf(current);
  return (
    <div className="flex items-center gap-0">
      {WORKFLOW_STEPS.map((step, i) => {
        const isPast    = i < idx;
        const isCurrent = i === idx;
        const label = STATUS_MAP[step]?.label ?? step;
        return (
          <div key={step} className="flex items-center">
            <div className={cn(
              "px-2.5 py-1 text-[9px] font-bold rounded-full border transition-all",
              isCurrent ? "bg-orange-500 text-white border-orange-500 shadow-sm" :
              isPast    ? "bg-green-50 text-green-600 border-green-200" :
              "bg-gray-50 text-gray-400 border-gray-200"
            )}>
              {isPast && <span className="mr-0.5">✓</span>}{label}
            </div>
            {i < WORKFLOW_STEPS.length - 1 && (
              <ArrowRight className={cn("w-3 h-3 mx-0.5 flex-shrink-0", isPast ? "text-green-400" : "text-gray-200")} />
            )}
          </div>
        );
      })}
    </div>
  );
}

// ── Finding detail panel ──────────────────────────────────────────────────────

type DetailTab = "overview" | "case" | "timeline";

function FindingDetailPanel({
  finding: f, onClose, onRefresh, canEdit,
}: {
  finding: Finding;
  onClose: () => void;
  onRefresh: () => void;
  canEdit: boolean;
}) {
  const [tab,         setTab]         = useState<DetailTab>("overview");
  const [activity,    setActivity]    = useState<ActivityEntry[]>([]);
  const [newComment,  setNewComment]  = useState("");
  const [posting,     setPosting]     = useState(false);
  const [acting,      setActing]      = useState(false);
  const [assigneeVal, setAssignee]    = useState(f.assignee ?? "");
  const [priorityVal, setPriority]    = useState(f.priority ?? 3);
  const [dueDate,     setDueDate]     = useState("");
  const [noteVal,     setNoteVal]     = useState(f.analyst_notes ?? "");
  const [copied,      setCopied]      = useState(false);

  const cveIds     = parseArr(f.cve_ids);
  const tags       = parseArr(f.tags);
  const evidence   = typeof f.evidence === "string" ? {} : (f.evidence ?? {});
  const actionPlan = parseArr(f.action_plan as unknown);
  const findingId  = f.external_id ?? f.display_id ?? `AL-${f.id}`;
  const cat        = catCfg(f.category);
  const score      = f.composite_score ?? f.score;

  useEffect(() => {
    fetch(`${SOC}/findings/${f.id}/activity`).then(r => r.ok ? r.json() : { activity: [] }).then(d => setActivity(d.activity ?? [])).catch(() => {});
  }, [f.id]);

  const act = async (newStatus: string) => {
    setActing(true);
    await patchFinding(f.id, { status: newStatus, actor: "analyst" });
    setActing(false); onRefresh();
  };

  const save = async () => {
    setActing(true);
    await patchFinding(f.id, { assignee: assigneeVal, priority: priorityVal, analyst_notes: noteVal, actor: "analyst" });
    setActing(false); onRefresh();
  };

  const postComment = async () => {
    if (!newComment.trim()) return;
    setPosting(true);
    await fetch(`${SOC}/findings/${f.id}/comments`, { method: "POST", headers: { "Content-Type": "application/json" }, body: JSON.stringify({ analyst: "analyst", comment: newComment }) });
    setNewComment(""); setPosting(false);
    fetch(`${SOC}/findings/${f.id}/activity`).then(r => r.json()).then(d => setActivity(d.activity ?? []));
  };

  const copyId = () => { navigator.clipboard?.writeText(findingId); setCopied(true); setTimeout(() => setCopied(false), 1400); };

  const TABS: { id: DetailTab; label: string; icon: React.ReactNode }[] = [
    { id: "overview", label: "Overview",  icon: <FileText className="w-3 h-3" /> },
    { id: "case",     label: "Case",      icon: <Shield className="w-3 h-3" /> },
    { id: "timeline", label: "Timeline",  icon: <Activity className="w-3 h-3" /> },
  ];

  const nextStatuses = STATUS_MAP[f.status]?.next ?? [];

  return (
    <div className="w-[480px] flex-shrink-0 bg-white border border-gray-200 rounded-2xl shadow-lg overflow-hidden self-start sticky top-0 max-h-[calc(100vh-120px)] flex flex-col al-panel-in">
      {/* Severity top stripe */}
      <div className={cn("h-1", f.severity === "critical" ? "bg-gradient-to-r from-red-500 to-red-600" : f.severity === "high" ? "bg-gradient-to-r from-amber-500 to-orange-500" : "bg-gradient-to-r from-orange-400 to-amber-400")} />

      {/* Header */}
      <div className="flex items-center justify-between px-4 py-2.5 border-b border-gray-100 bg-gray-50/60 flex-shrink-0">
        <div className="flex items-center gap-2 min-w-0 flex-wrap">
          {/* Finding ID chip */}
          <button onClick={copyId}
            className="flex items-center gap-1 px-2 py-0.5 bg-orange-50 border border-orange-200 rounded-lg text-[9px] font-black text-orange-700 hover:bg-orange-100 transition-colors font-mono">
            <Hash className="w-2.5 h-2.5" />
            {findingId}
            {copied ? <CheckCircle2 className="w-2.5 h-2.5 text-green-500" /> : <Copy className="w-2.5 h-2.5 opacity-50" />}
          </button>
          <span className={cn("px-2 py-0.5 text-[9px] font-bold rounded-full border uppercase tracking-wide", SEV_BADGE[f.severity])}>{f.severity}</span>
          {f.kev && <span className="px-1.5 py-0.5 bg-red-600 text-white rounded text-[8px] font-black badge-kev-pulse">KEV</span>}
          {f.exploit_available && <span className="px-1.5 py-0.5 bg-amber-100 text-amber-800 border border-amber-200 rounded text-[8px] font-bold">EXPLOIT</span>}
        </div>
        <button onClick={onClose} className="p-1.5 hover:bg-gray-200 rounded-lg transition-colors flex-shrink-0 ml-2">
          <XCircle className="w-3.5 h-3.5 text-gray-400" />
        </button>
      </div>

      {/* Tabs */}
      <div className="flex border-b border-gray-100 flex-shrink-0 bg-white">
        {TABS.map(t => (
          <button key={t.id} onClick={() => setTab(t.id)}
            className={cn("flex-1 flex items-center justify-center gap-1 py-2.5 text-[10px] font-bold transition-all relative", tab === t.id ? "text-orange-600" : "text-gray-400 hover:text-gray-600")}>
            {t.icon}{t.label}
            {tab === t.id && <span className="absolute bottom-0 left-2 right-2 h-0.5 bg-orange-500 rounded-t-full" style={{ animation: "tab-slide 0.2s ease both", transformOrigin: "left" }} />}
          </button>
        ))}
      </div>

      <div className="overflow-y-auto flex-1">

        {/* ── OVERVIEW ────────────────────────────────────────────────────── */}
        {tab === "overview" && (
          <div className="divide-y divide-gray-50">
            <div className="px-4 py-3">
              <p className="text-[12px] font-bold text-gray-900 leading-snug">{f.title}</p>
              <div className="flex flex-wrap gap-1 mt-1.5">
                <span className={cn("px-2 py-0.5 rounded-full border text-[9px] font-semibold", cat.bg, cat.color)}>{cat.label}</span>
                {f.mitre_technique && <span className="px-1.5 py-0.5 bg-indigo-50 text-indigo-700 border border-indigo-200 rounded text-[8px] font-mono font-semibold">{f.mitre_technique}</span>}
                {f.mitre_tactic && <span className="px-1.5 py-0.5 bg-purple-50 text-purple-600 border border-purple-200 rounded text-[8px] font-semibold">{f.mitre_tactic}</span>}
                {tags.map(t => <span key={t} className="px-1.5 py-0.5 bg-gray-100 text-gray-500 rounded text-[8px]">{t}</span>)}
              </div>
            </div>

            {/* Score tiles */}
            <div className="px-4 py-3 grid grid-cols-3 gap-2">
              {[
                { l: "Risk Score", v: `${score.toFixed(1)}/10`, c: score >= 8 ? "text-red-600" : score >= 6 ? "text-amber-600" : "text-blue-600", bg: score >= 8 ? "bg-red-50 border-red-100" : "bg-gray-50 border-gray-100" },
                { l: "CVSS",       v: f.cvss_score != null ? f.cvss_score.toFixed(1) : "—", c: f.cvss_score != null && f.cvss_score >= 9 ? "text-red-600" : "text-gray-600", bg: "bg-gray-50 border-gray-100" },
                { l: "EPSS",       v: f.epss_score != null ? `${Math.round(f.epss_score * 100)}%` : "—", c: f.epss_score != null && f.epss_score >= 0.5 ? "text-red-600" : "text-gray-600", bg: "bg-gray-50 border-gray-100" },
              ].map(s => (
                <div key={s.l} className={cn("rounded-xl border py-2.5 text-center al-bounce-in", s.bg)}>
                  <div className={cn("text-sm font-black leading-none", s.c)}>{s.v}</div>
                  <div className="text-[9px] text-gray-500 mt-1">{s.l}</div>
                </div>
              ))}
            </div>

            <div className="px-4 py-3">
              <div className="text-[9px] font-bold text-gray-400 uppercase tracking-wide mb-1.5">Description</div>
              <p className="text-[11px] text-gray-700 leading-relaxed">{f.description}</p>
            </div>

            {f.impact && (
              <div className="px-4 py-3">
                <div className="text-[9px] font-bold text-amber-600 uppercase tracking-wide mb-1.5 flex items-center gap-1"><AlertTriangle className="w-3 h-3" />Business Impact</div>
                <p className="text-[10px] text-amber-900 bg-amber-50 border border-amber-200 rounded-xl px-3 py-2 leading-relaxed">{f.impact}</p>
              </div>
            )}

            {/* CVEs */}
            {cveIds.length > 0 && (
              <div className="px-4 py-3">
                <div className="text-[9px] font-bold text-gray-400 uppercase tracking-wide mb-1.5">CVE References</div>
                <div className="flex flex-wrap gap-1">
                  {cveIds.map(c => (
                    <a key={c} href={`https://nvd.nist.gov/vuln/detail/${c}`} target="_blank" rel="noopener noreferrer"
                      className="flex items-center gap-0.5 font-mono text-[9px] px-1.5 py-0.5 bg-blue-50 text-blue-700 border border-blue-200 rounded hover:bg-blue-100 transition-colors">
                      {c}<ExternalLink className="w-2 h-2" />
                    </a>
                  ))}
                </div>
              </div>
            )}

            {/* Remediation */}
            {actionPlan.length > 0 && (
              <div className="px-4 py-3">
                <div className="text-[9px] font-bold text-green-700 uppercase tracking-wide mb-2 flex items-center gap-1"><Shield className="w-3 h-3" />Remediation</div>
                <ol className="space-y-2">
                  {(actionPlan as { title: string; detail: string }[]).map((step, i) => (
                    <li key={i} className="flex items-start gap-2">
                      <span className="w-4 h-4 rounded-full bg-orange-500 text-white flex items-center justify-center text-[8px] font-bold flex-shrink-0 mt-0.5">{i+1}</span>
                      <div><p className="text-[10px] font-semibold text-gray-800">{step.title}</p><p className="text-[10px] text-gray-600">{step.detail}</p></div>
                    </li>
                  ))}
                </ol>
              </div>
            )}

            {/* Evidence */}
            {Object.keys(evidence).length > 0 && (
              <div className="px-4 py-3">
                <div className="text-[9px] font-bold text-gray-400 uppercase tracking-wide mb-1.5">Evidence</div>
                <pre className="text-[9px] font-mono text-green-400 bg-gray-900 rounded-xl p-3 overflow-auto max-h-36 whitespace-pre-wrap break-words border border-gray-700">{JSON.stringify(evidence, null, 2)}</pre>
              </div>
            )}

            <div className="px-4 py-3">
              <div className="text-[9px] font-bold text-gray-400 uppercase tracking-wide mb-1.5">Detection Metadata</div>
              {[["Source", f.source ?? "—"],["Agent", f.agent_id],["First seen", fmtTs(f.first_detected_at)],["Last seen", fmtTs(f.last_detected_at)],["Scan count", String(f.scan_count)]].map(([l,v]) => (
                <div key={l} className="flex items-center gap-2 py-0.5">
                  <span className="w-20 text-[9px] text-gray-400 font-medium flex-shrink-0">{l}</span>
                  <span className="text-[10px] text-gray-700 font-mono">{v}</span>
                </div>
              ))}
            </div>
          </div>
        )}

        {/* ── CASE MANAGEMENT ─────────────────────────────────────────────── */}
        {tab === "case" && (
          <div className="divide-y divide-gray-50">
            {/* Resolved banner — shown for closed/accepted/FP findings */}
            {["closed","false_positive","accepted_risk","duplicate"].includes(f.status) && (
              <div className={cn(
                "mx-4 mt-3 flex items-center justify-between px-3 py-2.5 rounded-xl border text-[10px] font-semibold",
                f.status === "closed"         ? "bg-green-50 border-green-200 text-green-800" :
                f.status === "false_positive" ? "bg-gray-100 border-gray-300 text-gray-600" :
                f.status === "accepted_risk"  ? "bg-amber-50 border-amber-200 text-amber-800" :
                "bg-gray-50 border-gray-200 text-gray-500"
              )}>
                <div className="flex items-center gap-2">
                  {f.status === "closed"         && <CheckCircle2 className="w-3.5 h-3.5 text-green-600" />}
                  {f.status === "false_positive" && <XCircle className="w-3.5 h-3.5 text-gray-500" />}
                  {f.status === "accepted_risk"  && <Shield className="w-3.5 h-3.5 text-amber-600" />}
                  <span>
                    {f.status === "closed"         && "Finding closed"}
                    {f.status === "false_positive" && "Marked false positive"}
                    {f.status === "accepted_risk"  && "Risk accepted"}
                    {f.status === "duplicate"      && "Marked duplicate"}
                  </span>
                  {f.closed_at && <span className="opacity-60">· {relTime(f.closed_at)}</span>}
                </div>
                {canEdit && (
                  <button
                    onClick={() => act("triaging")}
                    disabled={acting}
                    className="flex items-center gap-1.5 px-2.5 py-1 bg-white border border-blue-200 text-blue-700 rounded-lg text-[9px] font-bold hover:bg-blue-50 transition-colors disabled:opacity-50"
                  >
                    <RotateCcw className="w-2.5 h-2.5" />Reopen
                  </button>
                )}
              </div>
            )}

            {/* Workflow strip */}
            <div className="px-4 py-3">
              <div className="text-[9px] font-bold text-gray-400 uppercase tracking-wide mb-2">Case Workflow</div>
              <div className="overflow-x-auto pb-1">
                <WorkflowStrip current={f.status} />
              </div>
            </div>

            {/* Status transitions */}
            <div className="px-4 py-3">
              <div className="text-[9px] font-bold text-gray-400 uppercase tracking-wide mb-2 flex items-center gap-1"><GitBranch className="w-3 h-3 text-orange-500" />Transition To</div>
              {nextStatuses.length > 0 ? (
                <div className="flex flex-wrap gap-1.5">
                  {nextStatuses.map(ns => {
                    const sc = STATUS_MAP[ns];
                    if (!sc) return null;
                    const isClose = ["closed","false_positive","accepted_risk","duplicate"].includes(ns);
                    return (
                      <button key={ns} onClick={() => act(ns)} disabled={acting || !canEdit}
                        className={cn(
                          "flex items-center gap-1.5 px-3 py-1.5 rounded-xl border text-[10px] font-bold transition-all hover:shadow-sm disabled:opacity-50",
                          sc.badge
                        )}>
                        {ns === "closed" && <CheckCircle2 className="w-3 h-3" />}
                        {ns === "false_positive" && <XCircle className="w-3 h-3" />}
                        {ns === "new" && <RotateCcw className="w-3 h-3" />}
                        {ns === "triaging" && <AlertTriangle className="w-3 h-3" />}
                        {ns === "investigating" && <Search className="w-3 h-3" />}
                        {ns === "in_remediation" && <Shield className="w-3 h-3" />}
                        {ns === "accepted_risk" && <Shield className="w-3 h-3" />}
                        {ns === "duplicate" && <Layers className="w-3 h-3" />}
                        {sc.label}
                        {isClose && <span className="text-[8px] opacity-60">→ close</span>}
                      </button>
                    );
                  })}
                </div>
              ) : (
                <p className="text-[10px] text-gray-400">No further transitions from this state.</p>
              )}
            </div>

            {/* Assignee + Priority + Due date */}
            <div className="px-4 py-3 space-y-3">
              <div className="text-[9px] font-bold text-gray-400 uppercase tracking-wide mb-1 flex items-center gap-1"><User className="w-3 h-3 text-orange-500" />Assignment</div>
              <div className="grid grid-cols-2 gap-3">
                <div>
                  <label className="text-[9px] text-gray-500 font-semibold block mb-1">Assignee</label>
                  <input type="text" placeholder="analyst@company.com" value={assigneeVal} onChange={e => setAssignee(e.target.value)}
                    className="w-full px-3 py-1.5 text-[11px] border border-gray-200 rounded-xl bg-white focus:outline-none focus:ring-2 focus:ring-orange-200 transition-all" />
                </div>
                <div>
                  <label className="text-[9px] text-gray-500 font-semibold block mb-1">Priority</label>
                  <select value={priorityVal} onChange={e => setPriority(Number(e.target.value))}
                    className="w-full px-3 py-1.5 text-[11px] border border-gray-200 rounded-xl bg-white focus:outline-none focus:ring-2 focus:ring-orange-200 cursor-pointer">
                    {Object.entries(PRIORITIES).map(([k, v]) => <option key={k} value={k}>{v.label}</option>)}
                  </select>
                </div>
              </div>
              <div>
                <label className="text-[9px] text-gray-500 font-semibold block mb-1 flex items-center gap-1"><Calendar className="w-3 h-3" />Due Date</label>
                <input type="date" value={dueDate} onChange={e => setDueDate(e.target.value)}
                  className="w-full px-3 py-1.5 text-[11px] border border-gray-200 rounded-xl bg-white focus:outline-none focus:ring-2 focus:ring-orange-200 transition-all" />
              </div>
              <div>
                <label className="text-[9px] text-gray-500 font-semibold block mb-1 flex items-center gap-1"><FileText className="w-3 h-3" />Analyst Notes</label>
                <textarea rows={3} value={noteVal} onChange={e => setNoteVal(e.target.value)} placeholder="Investigation notes, context, justification…"
                  className="w-full px-3 py-2 text-[11px] border border-gray-200 rounded-xl bg-white focus:outline-none focus:ring-2 focus:ring-orange-200 resize-none transition-all" />
              </div>
              {canEdit && (
                <button onClick={save} disabled={acting}
                  className="flex items-center gap-1.5 px-4 py-2 bg-orange-500 hover:bg-orange-600 text-white text-[10px] font-bold rounded-xl transition-all shadow-sm hover:shadow-md w-full justify-center disabled:opacity-60">
                  <CheckCircle2 className="w-3.5 h-3.5" />Save Case Updates
                </button>
              )}
            </div>

            {/* SLA */}
            {f.sla_status && (
              <div className="px-4 py-3">
                <div className="text-[9px] font-bold text-gray-400 uppercase tracking-wide mb-1.5 flex items-center gap-1"><Clock className="w-3 h-3" />SLA Status</div>
                <div className={cn("flex items-center gap-2 px-3 py-2 rounded-xl border text-[10px] font-semibold",
                  f.sla_status === "breached" ? "bg-red-50 border-red-200 text-red-700" :
                  f.sla_status === "warning"  ? "bg-amber-50 border-amber-200 text-amber-700" :
                  "bg-green-50 border-green-200 text-green-700")}>
                  <Clock className="w-3.5 h-3.5 flex-shrink-0" />
                  SLA {f.sla_status.toUpperCase()}
                  {f.sla_due && <span className="ml-auto text-[9px] opacity-70">Due {fmtTs(f.sla_due)}</span>}
                </div>
              </div>
            )}
          </div>
        )}

        {/* ── TIMELINE ────────────────────────────────────────────────────── */}
        {tab === "timeline" && (
          <div className="divide-y divide-gray-50">
            <div className="px-4 py-3">
              <div className="text-[9px] font-bold text-gray-400 uppercase tracking-wide mb-3 flex items-center gap-1"><Activity className="w-3 h-3 text-orange-500" />Activity Log</div>
              {activity.length === 0 ? (
                <div className="py-8 text-center text-[10px] text-gray-400">No activity recorded yet</div>
              ) : (
                <div className="relative space-y-3">
                  <div className="absolute left-3.5 top-0 bottom-0 w-0.5 bg-gray-100" />
                  {activity.map((a, i) => (
                    <div key={i} className="flex items-start gap-3 al-row-in" style={{ animationDelay: `${i * 40}ms` }}>
                      <div className="w-7 h-7 rounded-full bg-orange-50 border-2 border-white ring-1 ring-gray-100 flex items-center justify-center flex-shrink-0 z-10">
                        <span className="text-[9px] font-black text-orange-600">{(a.actor?.[0] ?? "?").toUpperCase()}</span>
                      </div>
                      <div className="flex-1 min-w-0 pb-2">
                        <div className="flex items-center gap-1.5 flex-wrap">
                          <span className="text-[10px] font-bold text-gray-700">{a.actor}</span>
                          <span className="text-[10px] text-gray-500">{a.action.replace(/_/g, " ")}</span>
                          {a.old_value && a.new_value && (
                            <span className="text-[9px] text-gray-400 font-mono">{a.old_value} <ArrowRight className="w-2 h-2 inline" /> {a.new_value}</span>
                          )}
                          <span className="ml-auto text-[9px] text-gray-400 flex-shrink-0">{relTime(a.created_at)}</span>
                        </div>
                        {a.comment && <p className="text-[10px] text-gray-600 mt-0.5 bg-gray-50 rounded-lg px-2 py-1 border border-gray-100">{a.comment}</p>}
                      </div>
                    </div>
                  ))}
                </div>
              )}
            </div>

            {/* Add comment */}
            {canEdit && (
              <div className="px-4 py-3">
                <div className="text-[9px] font-bold text-gray-400 uppercase tracking-wide mb-2 flex items-center gap-1"><MessageSquare className="w-3 h-3 text-blue-500" />Add Note</div>
                <div className="space-y-2">
                  <textarea rows={2} value={newComment} onChange={e => setNewComment(e.target.value)}
                    onKeyDown={e => { if (e.key === "Enter" && e.ctrlKey) postComment(); }}
                    placeholder="Add investigation note… (Ctrl+Enter to post)"
                    className="w-full px-3 py-2 text-[11px] border border-gray-200 rounded-xl bg-white focus:outline-none focus:ring-2 focus:ring-orange-200 resize-none transition-all" />
                  <button onClick={postComment} disabled={posting || !newComment.trim()}
                    className="flex items-center gap-1.5 px-3 py-1.5 bg-orange-500 hover:bg-orange-600 text-white text-[10px] font-bold rounded-xl transition-all disabled:opacity-50">
                    <Send className="w-3 h-3" />{posting ? "Posting…" : "Post Note"}
                  </button>
                </div>
              </div>
            )}
          </div>
        )}
      </div>
    </div>
  );
}

// ── Main Findings Page ────────────────────────────────────────────────────────

export default function ThreatQueue() {
  const { can } = useRBAC();

  // Data
  const [findings, setFindings]   = useState<Finding[]>([]);
  const [loading,  setLoading]    = useState(true);
  const [error,    setError]      = useState<string | null>(null);
  const [lastSync, setLastSync]   = useState(0);

  // Selection
  const [selected, setSelected]   = useState<Set<number>>(new Set());
  const [bulkActing, setBulkActing] = useState(false);

  // Expanded detail
  const [detailId, setDetailId]   = useState<number | null>(null);

  // View mode — controls active_only / view param
  const [viewMode, setViewMode]   = useState<"active" | "closed" | "all">("active");

  // Filters
  const [catTab,   setCatTab]     = useState("all");
  const [severity, setSeverity]   = useState("");
  const [status,   setStatus]     = useState("");
  const [slaOnly,  setSlaOnly]    = useState(false);
  const [kevOnly,  setKevOnly]    = useState(false);
  const [search,   setSearch]     = useState("");
  const [rawSearch,setRawSearch]  = useState("");
  const [sortKey,  setSortKey]    = useState("composite_score");
  const [sortAsc,  setSortAsc]    = useState(false);
  const debRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  // Pagination
  const PAGE_SIZE = 50;
  const [page, setPage] = useState(0);

  // Reset to first page whenever any filter / sort / view changes
  useEffect(() => { setPage(0); }, [catTab, severity, status, slaOnly, kevOnly, search, sortKey, sortAsc, viewMode]);

  const load = useCallback(async () => {
    const p = new URLSearchParams({ limit: "500", sort_by: sortKey, view: viewMode });
    if (severity) p.set("severity", severity);
    // Don't send status param when view=closed (backend handles terminal states)
    if (status && viewMode !== "closed") p.set("status", status);
    if (slaOnly)  p.set("sla_breached", "true");
    if (search)   p.set("search",   search);
    try {
      const r = await fetch(`${SOC}/findings?${p}`);
      if (!r.ok) throw new Error(`${r.status}`);
      const d = await r.json();
      setFindings(d.findings ?? []);
      setError(null);
    } catch (e) { setError(String(e)); }
    finally { setLoading(false); setLastSync(Math.floor(Date.now() / 1000)); }
  }, [severity, status, slaOnly, search, sortKey, viewMode]);

  useEffect(() => { load(); }, [load]);
  useEffect(() => { const t = setInterval(load, 30_000); return () => clearInterval(t); }, [load]);

  const handleSearch = (v: string) => {
    setRawSearch(v);
    if (debRef.current) clearTimeout(debRef.current);
    debRef.current = setTimeout(() => setSearch(v), 300);
  };

  // Category filter
  const filtered = findings.filter(f => {
    if (catTab !== "all") {
      const k = catKey(f.category);
      const grouped: Record<string, string[]> = {
        execution: ["execution","malware","process","script"],
        network:   ["network","connection","c2"],
        package:   ["package","vulnerability","cve","sbom"],
        persistence:["persistence","service","task","config","backdoor"],
        user:      ["user","identity","account","credential"],
        security:  ["security","posture","sip","firewall"],
      };
      const allowed = grouped[catTab] ?? [catTab];
      if (!allowed.includes(k) && !f.category.toLowerCase().includes(catTab)) return false;
    }
    if (kevOnly && !f.kev) return false;
    return true;
  });

  // Sort
  const sorted = [...filtered].sort((a, b) => {
    let d = 0;
    if (sortKey === "composite_score") d = (b.composite_score ?? b.score) - (a.composite_score ?? a.score);
    else if (sortKey === "first_detected_at") d = b.first_detected_at - a.first_detected_at;
    else if (sortKey === "severity") {
      const o: Record<string, number> = { critical: 4, high: 3, medium: 2, low: 1, info: 0 };
      d = (o[b.severity] ?? 0) - (o[a.severity] ?? 0);
    }
    return sortAsc ? -d : d;
  });

  const toggleSort = (key: string) => { sortKey === key ? setSortAsc(a => !a) : (setSortKey(key), setSortAsc(false)); };

  // Pagination slice
  const totalPages = Math.max(1, Math.ceil(sorted.length / PAGE_SIZE));
  const pageItems  = sorted.slice(page * PAGE_SIZE, (page + 1) * PAGE_SIZE);
  const pageStart  = page * PAGE_SIZE + 1;
  const pageEnd    = Math.min((page + 1) * PAGE_SIZE, sorted.length);

  // Selection
  const toggleOne  = (id: number) => setSelected(prev => { const n = new Set(prev); n.has(id) ? n.delete(id) : n.add(id); return n; });
  const toggleAll  = () => setSelected(prev => prev.size === sorted.length ? new Set() : new Set(sorted.map(f => f.id)));
  const clearSel   = () => setSelected(new Set());

  const doBulk = async (action: string, value?: string) => {
    if (!can("bulk_action") || selected.size === 0) return;
    setBulkActing(true);
    await bulkAction(Array.from(selected), action, value);
    clearSel();
    await load();
    setBulkActing(false);
  };

  // ── Inline quick actions (per-row buttons) ───────────────────────────────
  const [quickActing, setQuickActing] = useState<number | null>(null); // finding id being acted on

  const quickAct = async (findingId: number, endpoint: string) => {
    setQuickActing(findingId);
    try {
      await fetch(`${SOC}/findings/${findingId}/${endpoint}`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ actor: "analyst" }),
      });
      // Optimistic: close the detail panel if it was open for this finding
      if (detailId === findingId) setDetailId(null);
      await load();
    } finally {
      setQuickActing(null);
    }
  };

  // Stats
  const total      = findings.length;
  const critical   = findings.filter(f => f.severity === "critical").length;
  const high       = findings.filter(f => f.severity === "high").length;
  const isNew      = findings.filter(f => f.status === "new").length;
  const slaBreached= findings.filter(f => f.sla_status === "breached").length;
  const unassigned = findings.filter(f => !f.assignee && !["closed","false_positive","accepted_risk"].includes(f.status)).length;
  const kevCount   = findings.filter(f => f.kev).length;

  const detailFinding = sorted.find(f => f.id === detailId) ?? null;

  // Sortable header
  const SortTh = ({ label, k }: { label: string; k: string }) => (
    <th onClick={() => toggleSort(k)} className="px-3 py-2.5 text-left text-[9px] font-black text-gray-400 uppercase tracking-wider cursor-pointer hover:text-gray-600 select-none whitespace-nowrap">
      <span className="flex items-center gap-1">{label}
        {sortKey === k && <span className="text-orange-500">{sortAsc ? "↑" : "↓"}</span>}
      </span>
    </th>
  );

  return (
    <div className="space-y-4 pb-6">

      {/* ── Header ─────────────────────────────────────────────────────────── */}
      <div className="bg-white border border-gray-200 rounded-2xl shadow-sm overflow-hidden">
        <div className="h-1 bg-gradient-to-r from-orange-400 via-amber-400 to-orange-500 relative overflow-hidden">
          <div className="absolute inset-0 al-scan" style={{ background: "linear-gradient(90deg,transparent,rgba(255,255,255,0.5),transparent)", width: "40%" }} />
        </div>
        <div className="p-5">
          <div className="flex items-start justify-between gap-4">
            <div className="flex items-start gap-3">
              <div className="w-10 h-10 rounded-xl bg-orange-50 border border-orange-100 flex items-center justify-center flex-shrink-0">
                <AlertTriangle className="w-5 h-5 text-orange-500" />
              </div>
              <div>
                <div className="flex items-center gap-2">
                  <h1 className="text-base font-bold text-gray-900">Findings</h1>
                  <span className="px-2 py-0.5 bg-orange-50 text-orange-700 border border-orange-200 rounded-full text-[9px] font-black">LIVE</span>
                </div>
                <p className="text-xs text-gray-500 mt-0.5">
                  All detection findings · case management · SLA tracking · bulk actions · auto-refresh 30s
                </p>
              </div>
            </div>
            <div className="flex items-center gap-2">
              <div className="flex items-center gap-1.5 px-3 py-1.5 bg-gray-50 border border-gray-200 rounded-xl text-[9px] text-gray-500 font-medium">
                <span className="w-1.5 h-1.5 rounded-full bg-green-500 al-heartbeat" />
                {lastSync ? `Synced ${relTime(lastSync)}` : "Loading…"}
              </div>
              <button onClick={load} className="flex items-center gap-1.5 px-3 py-2 rounded-xl bg-gray-100 hover:bg-orange-50 hover:border-orange-200 border border-gray-200 text-gray-600 hover:text-orange-600 text-xs font-semibold transition-all">
                <RefreshCw className={cn("w-3.5 h-3.5", loading && "animate-spin")} />
              </button>
            </div>
          </div>

          {/* KPI strip */}
          <div className="grid grid-cols-7 gap-2 mt-4 pt-4 border-t border-gray-100">
            <KpiTile label="Total"       value={total}       color="text-gray-800"   bg="bg-gray-50 border-gray-200"     icon={<AlertCircle className="w-3 h-3" />}     delay={0}   />
            <KpiTile label="Critical"    value={critical}    color="text-red-700"    bg="bg-red-50 border-red-200"       icon={<AlertTriangle className="w-3 h-3" />}   delay={40}  />
            <KpiTile label="High"        value={high}        color="text-amber-700"  bg="bg-amber-50 border-amber-200"   icon={<Zap className="w-3 h-3" />}             delay={80}  />
            <KpiTile label="New"         value={isNew}       color={isNew > 0 ? "text-red-600" : "text-green-600"} bg={isNew > 0 ? "bg-red-50 border-red-200" : "bg-green-50 border-green-200"} icon={<Radio className="w-3 h-3" />} delay={120} />
            <KpiTile label="SLA Breach"  value={slaBreached} color={slaBreached > 0 ? "text-red-600" : "text-green-600"} bg={slaBreached > 0 ? "bg-red-50 border-red-200" : "bg-green-50 border-green-200"} icon={<Clock className="w-3 h-3" />} delay={160} />
            <KpiTile label="Unassigned"  value={unassigned}  color={unassigned > 0 ? "text-amber-700" : "text-green-600"} bg={unassigned > 0 ? "bg-amber-50 border-amber-200" : "bg-green-50 border-green-200"} icon={<User className="w-3 h-3" />} delay={200} />
            <KpiTile label="KEV Listed"  value={kevCount}    color={kevCount > 0 ? "text-red-700" : "text-gray-500"}    bg={kevCount > 0 ? "bg-red-50 border-red-200" : "bg-gray-50 border-gray-200"}   icon={<Zap className="w-3 h-3" />} delay={240} />
          </div>
        </div>
      </div>

      {error && (
        <div className="px-4 py-3 bg-red-50 border border-red-200 rounded-2xl text-xs text-red-700 flex items-center gap-2 al-row-in">
          <AlertTriangle className="w-3.5 h-3.5 flex-shrink-0" />{error}
        </div>
      )}

      {/* ── View mode toggle ─────────────────────────────────────────────────── */}
      <div className="flex items-center gap-2">
        {([
          { id: "active", label: "Active",   desc: "Open findings",          color: "bg-orange-500 text-white", badge: findings.length },
          { id: "closed", label: "Resolved", desc: "Closed / FP / Accepted", color: "bg-green-600 text-white",  badge: null },
          { id: "all",    label: "All",       desc: "Every finding",          color: "bg-gray-700 text-white",   badge: null },
        ] as { id: "active"|"closed"|"all"; label: string; desc: string; color: string; badge: number|null }[]).map(v => (
          <button
            key={v.id}
            onClick={() => { setViewMode(v.id); setStatus(""); }}
            className={cn(
              "flex items-center gap-2 px-4 py-2 rounded-xl border text-[11px] font-bold transition-all",
              viewMode === v.id
                ? `${v.color} border-transparent shadow-sm`
                : "bg-white text-gray-600 border-gray-200 hover:border-gray-300 hover:bg-gray-50"
            )}
          >
            {v.label}
            {v.id === "active" && (
              <span className={cn("px-1.5 py-0.5 rounded-full text-[9px] font-black",
                viewMode === "active" ? "bg-white/25 text-white" : "bg-gray-100 text-gray-500")}>
                {findings.length}
              </span>
            )}
            <span className={cn("text-[9px] hidden sm:inline", viewMode === v.id ? "opacity-70" : "text-gray-400")}>
              {v.desc}
            </span>
          </button>
        ))}
      </div>

      {/* ── Category tabs ────────────────────────────────────────────────────── */}
      <div className="flex items-center gap-1 bg-white border border-gray-200 rounded-2xl p-1.5 shadow-sm overflow-x-auto">
        {CAT_GROUPS.map(g => {
          const count = g.key === "all" ? findings.length : findings.filter(f => {
            const k = catKey(f.category);
            const grouped: Record<string, string[]> = {
              execution: ["execution","malware","process"],
              network:   ["network","connection"],
              package:   ["package","vulnerability"],
              persistence:["persistence","service","task","config"],
              user:      ["user","identity","account"],
              security:  ["security","posture"],
            };
            return (grouped[g.key] ?? [g.key]).includes(k) || f.category.toLowerCase().includes(g.key);
          }).length;
          return (
            <button key={g.key} onClick={() => setCatTab(g.key)}
              className={cn("flex items-center gap-1.5 py-1.5 px-3 rounded-xl text-[11px] font-bold whitespace-nowrap transition-all flex-shrink-0",
                catTab === g.key ? "bg-orange-500 text-white shadow-sm" : "text-gray-500 hover:bg-gray-50 hover:text-gray-700")}>
              {g.label}
              <span className={cn("px-1.5 py-0.5 rounded-full text-[8px] font-black", catTab === g.key ? "bg-white/20 text-white" : "bg-gray-100 text-gray-500")}>
                {count}
              </span>
            </button>
          );
        })}
      </div>

      {/* ── Main table ───────────────────────────────────────────────────────── */}
      <div className="flex gap-4 items-start">
        <div className="flex-1 min-w-0 bg-white border border-gray-200 rounded-2xl shadow-sm overflow-hidden">
          <div className="h-0.5 bg-gradient-to-r from-orange-400 via-amber-400 to-orange-500" />

          {/* Filter bar + bulk actions */}
          <div className="flex items-center gap-2 px-5 py-3 border-b border-gray-100 bg-gray-50/60 flex-wrap">
            <Filter className="w-3.5 h-3.5 text-gray-400 flex-shrink-0" />
            <div className="relative">
              <Search className="absolute left-2.5 top-1/2 -translate-y-1/2 w-3 h-3 text-gray-400 pointer-events-none" />
              <input value={rawSearch} onChange={e => handleSearch(e.target.value)} placeholder="Search findings…"
                className="pl-7 pr-3 py-1.5 text-[11px] border border-gray-200 rounded-xl bg-white focus:outline-none focus:ring-2 focus:ring-orange-200 w-44 transition-all" />
            </div>
            <select value={severity} onChange={e => setSeverity(e.target.value)}
              className="px-2 py-1.5 text-[10px] border border-gray-200 rounded-xl bg-white text-gray-700 focus:outline-none cursor-pointer">
              <option value="">All Severity</option>
              {["critical","high","medium","low"].map(s => <option key={s} value={s}>{s[0].toUpperCase() + s.slice(1)}</option>)}
            </select>
            <select value={status} onChange={e => setStatus(e.target.value)}
              className="px-2 py-1.5 text-[10px] border border-gray-200 rounded-xl bg-white text-gray-700 focus:outline-none cursor-pointer">
              <option value="">All Status</option>
              {STATUS_FLOW.map(s => <option key={s.key} value={s.key}>{s.label}</option>)}
            </select>
            <label className="flex items-center gap-1 cursor-pointer text-[10px] text-gray-600 font-medium">
              <input type="checkbox" checked={slaOnly} onChange={e => setSlaOnly(e.target.checked)} className="rounded accent-orange-500" />
              SLA Breached
            </label>
            <label className="flex items-center gap-1 cursor-pointer text-[10px] text-gray-600 font-medium">
              <input type="checkbox" checked={kevOnly} onChange={e => setKevOnly(e.target.checked)} className="rounded accent-red-500" />
              KEV Only
            </label>

            {/* Bulk action strip */}
            {selected.size > 0 && can("bulk_action") && (
              <div className="ml-auto flex items-center gap-1.5 pl-3 border-l border-gray-200 flex-shrink-0 flex-wrap">
                <span className="px-2.5 py-1 bg-orange-500 text-white text-[10px] font-black rounded-xl al-heartbeat">
                  {selected.size} selected
                </span>
                {[
                  { label: "Triage",       action: "triaging",       cls: "bg-amber-50 text-amber-700 border-amber-200",  icon: <AlertTriangle className="w-3 h-3" /> },
                  { label: "Investigate",  action: "investigating",  cls: "bg-blue-50 text-blue-700 border-blue-200",     icon: <ChevronRight className="w-3 h-3" /> },
                  { label: "Close",        action: "closed",         cls: "bg-green-50 text-green-700 border-green-200",  icon: <CheckCircle2 className="w-3 h-3" /> },
                  { label: "Accept Risk",  action: "accepted_risk",  cls: "bg-amber-50 text-amber-600 border-amber-200",  icon: <Shield className="w-3 h-3" /> },
                  { label: "False Pos.",   action: "false_positive", cls: "bg-gray-100 text-gray-500 border-gray-300",    icon: <XCircle className="w-3 h-3" /> },
                ].map(b => (
                  <button key={b.action} onClick={() => doBulk("status", b.action)} disabled={bulkActing}
                    className={cn("flex items-center gap-1 px-2.5 py-1.5 rounded-xl border text-[10px] font-bold transition-all hover:shadow-sm disabled:opacity-50", b.cls)}>
                    {b.icon}{b.label}
                  </button>
                ))}
                <button onClick={clearSel} className="p-1.5 rounded-xl hover:bg-gray-100 text-gray-400 hover:text-gray-600">
                  <XCircle className="w-3.5 h-3.5" />
                </button>
              </div>
            )}

            {selected.size === 0 && (
              <div className="ml-auto text-[10px] text-gray-400 flex items-center gap-1.5">
                <span className="w-1.5 h-1.5 rounded-full bg-green-500 al-heartbeat" />
                {sorted.length} of {total} findings
              </div>
            )}
          </div>

          {/* Table */}
          <div className="overflow-x-auto">
            <table className="w-full">
              <thead>
                <tr className="bg-gray-50/80 border-b border-gray-100">
                  <th className="pl-4 pr-2 py-2.5 w-10">
                    <button onClick={toggleAll} className="flex items-center">
                      {selected.size > 0 && selected.size === sorted.length
                        ? <CheckSquare className="w-3.5 h-3.5 text-orange-500" />
                        : selected.size > 0
                        ? <CheckSquare className="w-3.5 h-3.5 text-orange-300" />
                        : <Square className="w-3.5 h-3.5 text-gray-300 hover:text-gray-500" />}
                    </button>
                  </th>
                  <th className="px-3 py-2.5 text-left text-[9px] font-black text-gray-400 uppercase tracking-wider whitespace-nowrap">ID</th>
                  <SortTh label="Finding" k="title" />
                  <th className="px-3 py-2.5 text-left text-[9px] font-black text-gray-400 uppercase tracking-wider">Category</th>
                  <SortTh label="Score" k="composite_score" />
                  <th className="px-3 py-2.5 text-left text-[9px] font-black text-gray-400 uppercase tracking-wider">Status</th>
                  <th className="px-3 py-2.5 text-left text-[9px] font-black text-gray-400 uppercase tracking-wider">SLA</th>
                  <th className="px-3 py-2.5 text-left text-[9px] font-black text-gray-400 uppercase tracking-wider">Assignee</th>
                  <th className="px-3 py-2.5 text-left text-[9px] font-black text-gray-400 uppercase tracking-wider">Agent</th>
                  <SortTh label="Detected" k="first_detected_at" />
                  <th className="px-2 py-2.5 text-left text-[9px] font-black text-gray-400 uppercase tracking-wider whitespace-nowrap w-[120px]">Actions</th>
                  <th className="pr-3 py-2.5 w-6" />
                </tr>
              </thead>
              <tbody>
                {loading && findings.length === 0 ? (
                  Array.from({ length: 6 }).map((_, i) => (
                    <tr key={i} className="border-b border-gray-50">
                      {Array.from({ length: 11 }).map((_, j) => (
                        <td key={j} className="px-3 py-3"><div className="h-3 bg-gray-100 rounded-full animate-pulse" style={{ width: j === 2 ? "70%" : "40%", animationDelay: `${i*80+j*30}ms` }} /></td>
                      ))}
                    </tr>
                  ))
                ) : sorted.length === 0 ? (
                  <tr><td colSpan={11} className="py-20 text-center">
                    <AlertCircle className="w-10 h-10 text-gray-200 mx-auto mb-3" />
                    <p className="text-[11px] text-gray-400 font-medium">No findings match the current filters</p>
                  </td></tr>
                ) : (
                  pageItems.map((f, idx) => {
                    const isChecked = selected.has(f.id);
                    const isDetail  = detailId === f.id;
                    const isCrit    = f.severity === "critical";
                    const isSlaBreached = f.sla_status === "breached";
                    const cat       = catCfg(f.category);
                    const sc        = STATUS_MAP[f.status];
                    const score     = f.composite_score ?? f.score;
                    const fid       = f.external_id ?? f.display_id ?? `AL-${String(f.id).padStart(5, "0")}`;

                    return (
                      <tr key={f.id}
                        className={cn(
                          "border-b border-gray-100/80 transition-all al-row-in group",
                          isDetail  ? "bg-orange-50/60 shadow-[inset_3px_0_0_#f97316]" :
                          isChecked ? "bg-orange-50/40 shadow-[inset_3px_0_0_#fb923c]" :
                          isSlaBreached ? "bg-red-50/20 hover:bg-red-50/40 shadow-[inset_3px_0_0_#ef4444]" :
                          isCrit ? cn("al-glow-critical hover:bg-red-50/20 shadow-[inset_3px_0_0_#ef4444]") :
                          f.severity === "high" ? "hover:bg-amber-50/20 shadow-[inset_3px_0_0_#f59e0b]" :
                          "hover:bg-gray-50/80",
                          isCrit && "al-glow-critical",
                        )}
                        style={{ animationDelay: `${Math.min(idx * 25, 400)}ms` }}
                      >
                        {/* Checkbox */}
                        <td className="pl-4 pr-2 py-3 w-10">
                          <button onClick={() => toggleOne(f.id)} className="flex items-center">
                            {isChecked
                              ? <CheckSquare className="w-3.5 h-3.5 text-orange-500" />
                              : <Square className="w-3.5 h-3.5 text-gray-200 group-hover:text-gray-400 transition-colors" />}
                          </button>
                        </td>

                        {/* Finding ID */}
                        <td className="px-3 py-3 w-28">
                          <span className="font-mono text-[9px] font-bold text-orange-700 bg-orange-50 border border-orange-200 px-1.5 py-0.5 rounded whitespace-nowrap">
                            {fid}
                          </span>
                        </td>

                        {/* Title + badges */}
                        <td className="px-3 py-3 max-w-[220px] cursor-pointer" onClick={() => setDetailId(isDetail ? null : f.id)}>
                          <div className="flex items-start gap-2">
                            <div className={cn("relative flex-shrink-0 mt-1", isCrit && "al-sonar-dot")}>
                              <div className={cn("w-2 h-2 rounded-full", SEV_DOT[f.severity] ?? "bg-gray-300")} />
                            </div>
                            <div className="min-w-0">
                              <div className="text-[11px] font-semibold text-gray-800 leading-tight truncate" title={f.title}>{f.title}</div>
                              <div className="flex items-center gap-1 mt-0.5 flex-wrap">
                                <span className={cn("px-1.5 py-0.5 text-[8px] font-bold rounded-full border uppercase", SEV_BADGE[f.severity])}>{f.severity}</span>
                                {f.kev && <span className="px-1 py-0.5 bg-red-600 text-white rounded text-[7px] font-black">KEV</span>}
                                {f.exploit_available && <span className="px-1 py-0.5 bg-amber-100 text-amber-800 border border-amber-200 rounded text-[7px] font-bold">EXP</span>}
                                {f.mitre_technique && <span className="font-mono text-[8px] text-indigo-600">{f.mitre_technique}</span>}
                              </div>
                            </div>
                          </div>
                        </td>

                        {/* Category */}
                        <td className="px-3 py-3">
                          <span className={cn("px-2 py-0.5 rounded-full border text-[8px] font-semibold whitespace-nowrap", cat.bg, cat.color)}>
                            {cat.label}
                          </span>
                        </td>

                        {/* Score */}
                        <td className="px-3 py-3 w-24">
                          <div className="flex items-center gap-1.5">
                            <div className="w-10 h-1.5 bg-gray-100 rounded-full overflow-hidden">
                              <div className={cn("h-full rounded-full al-bar-fill", score >= 8 ? "bg-red-500" : score >= 6 ? "bg-amber-500" : "bg-blue-400")}
                                style={{ width: `${Math.min(100, score * 10)}%` }} />
                            </div>
                            <span className={cn("text-[10px] font-black tabular-nums", score >= 8 ? "text-red-600" : score >= 6 ? "text-amber-600" : "text-blue-600")}>{score.toFixed(1)}</span>
                          </div>
                        </td>

                        {/* Status */}
                        <td className="px-3 py-3">
                          {sc && <span className={cn("px-2 py-0.5 text-[8px] font-bold rounded-full border whitespace-nowrap", sc.badge)}>{sc.label}</span>}
                        </td>

                        {/* SLA */}
                        <td className="px-3 py-3 w-24">
                          {f.sla_status ? (
                            <span className={cn("px-2 py-0.5 text-[8px] font-bold rounded-full border whitespace-nowrap",
                              f.sla_status === "breached" ? "bg-red-50 text-red-700 border-red-300 al-heartbeat" :
                              f.sla_status === "warning"  ? "bg-amber-50 text-amber-700 border-amber-200" :
                              "bg-green-50 text-green-700 border-green-200")}>
                              {f.sla_status}
                            </span>
                          ) : <span className="text-gray-200 text-[9px]">—</span>}
                        </td>

                        {/* Assignee */}
                        <td className="px-3 py-3">
                          {f.assignee
                            ? <div className="flex items-center gap-1"><div className="w-4 h-4 rounded-full bg-orange-100 flex items-center justify-center text-[7px] font-black text-orange-600 flex-shrink-0">{f.assignee[0].toUpperCase()}</div><span className="text-[9px] text-gray-600 truncate max-w-[80px]">{f.assignee}</span></div>
                            : <span className="text-[9px] text-amber-500 font-semibold flex items-center gap-0.5"><User className="w-2.5 h-2.5" />Unassigned</span>}
                        </td>

                        {/* Agent */}
                        <td className="px-3 py-3 text-[9px] font-mono text-gray-400">{f.agent_id?.slice(0, 12)}</td>

                        {/* Time */}
                        <td className="px-3 py-3 text-[9px] text-gray-400 whitespace-nowrap">
                          <div>{relTime(f.first_detected_at)}</div>
                          <div className="text-gray-300">seen {f.scan_count}×</div>
                        </td>

                        {/* Quick actions — visible on row hover */}
                        <td className="pr-2 py-2.5 w-[120px]">
                          <div className="flex items-center gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
                            {(() => {
                              const isActing = quickActing === f.id;
                              const isClosed = ["closed","false_positive","accepted_risk","duplicate"].includes(f.status);
                              if (isClosed) {
                                return (
                                  <button
                                    onClick={e => { e.stopPropagation(); quickAct(f.id, "reopen"); }}
                                    disabled={isActing || !can("update_finding")}
                                    title="Reopen finding"
                                    className="flex items-center gap-1 px-2 py-1 rounded-lg text-[9px] font-bold bg-blue-50 text-blue-700 border border-blue-200 hover:bg-blue-100 transition-colors disabled:opacity-50 whitespace-nowrap"
                                  >
                                    <RotateCcw className="w-2.5 h-2.5" />
                                    {isActing ? "…" : "Reopen"}
                                  </button>
                                );
                              }
                              return (
                                <>
                                  <button
                                    onClick={e => { e.stopPropagation(); quickAct(f.id, "close"); }}
                                    disabled={isActing || !can("update_finding")}
                                    title="Close finding"
                                    className="flex items-center gap-1 px-2 py-1 rounded-lg text-[9px] font-bold bg-green-50 text-green-700 border border-green-200 hover:bg-green-100 transition-colors disabled:opacity-50 whitespace-nowrap"
                                  >
                                    <CheckCircle2 className="w-2.5 h-2.5" />
                                    {isActing ? "…" : "Close"}
                                  </button>
                                  <button
                                    onClick={e => { e.stopPropagation(); quickAct(f.id, "accept-risk"); }}
                                    disabled={isActing || !can("update_finding")}
                                    title="Accept risk"
                                    className="flex items-center gap-1 px-2 py-1 rounded-lg text-[9px] font-bold bg-amber-50 text-amber-700 border border-amber-200 hover:bg-amber-100 transition-colors disabled:opacity-50 whitespace-nowrap"
                                  >
                                    <Shield className="w-2.5 h-2.5" />
                                    {isActing ? "…" : "Accept"}
                                  </button>
                                  <button
                                    onClick={e => { e.stopPropagation(); quickAct(f.id, "false-positive"); }}
                                    disabled={isActing || !can("update_finding")}
                                    title="Mark false positive"
                                    className="flex items-center gap-1 px-2 py-1 rounded-lg text-[9px] font-bold bg-gray-50 text-gray-500 border border-gray-200 hover:bg-gray-100 transition-colors disabled:opacity-50 whitespace-nowrap"
                                  >
                                    <XCircle className="w-2.5 h-2.5" />
                                    FP
                                  </button>
                                </>
                              );
                            })()}
                          </div>
                        </td>

                        {/* Expand */}
                        <td className="pr-3 py-3 w-6 text-gray-300 cursor-pointer" onClick={() => setDetailId(isDetail ? null : f.id)}>
                          {isDetail ? <ChevronDown className="w-3.5 h-3.5 text-orange-400" /> : <ChevronRight className="w-3.5 h-3.5 opacity-0 group-hover:opacity-100 transition-opacity" />}
                        </td>
                      </tr>
                    );
                  })
                )}
              </tbody>
            </table>
          </div>

          {/* Footer + Pagination */}
          {sorted.length > 0 && (
            <div className="border-t border-gray-100 bg-gray-50/60">
              {/* Summary row */}
              <div className="px-5 py-2 flex items-center justify-between text-[10px] border-b border-gray-100">
                <div className="flex items-center gap-3">
                  <span className="font-bold text-gray-700">
                    Showing <span className="text-orange-600">{pageStart}–{pageEnd}</span> of <span className="text-gray-900">{sorted.length}</span> findings
                    {sorted.length !== total && <span className="text-gray-400 ml-1">(filtered from {total})</span>}
                  </span>
                  {critical > 0    && <span className="text-red-600 font-bold flex items-center gap-1"><span className="w-1.5 h-1.5 rounded-full bg-red-500 animate-pulse" />{critical} critical</span>}
                  {slaBreached > 0 && <span className="text-red-500 font-bold">{slaBreached} SLA breach</span>}
                  {unassigned > 0  && <span className="text-amber-600 font-semibold">{unassigned} unassigned</span>}
                </div>
                <div className="text-gray-400">
                  {selected.size > 0
                    ? <span className="text-orange-500 font-bold">{selected.size} selected across all pages · bulk actions above</span>
                    : "Click row to open case · ☐ to select"}
                </div>
              </div>

              {/* Pagination controls */}
              <div className="px-5 py-2.5 flex items-center justify-between">
                {/* Prev */}
                <button onClick={() => setPage(p => Math.max(0, p - 1))} disabled={page === 0}
                  className="flex items-center gap-1 px-3 py-1.5 text-[10px] font-semibold rounded-xl border border-gray-200 bg-white text-gray-600 hover:bg-gray-50 disabled:opacity-40 disabled:cursor-not-allowed transition-all">
                  ← Prev
                </button>

                {/* Page chips */}
                <div className="flex items-center gap-1">
                  {Array.from({ length: totalPages }, (_, i) => {
                    const show = i === 0 || i === totalPages - 1 || Math.abs(i - page) <= 1;
                    const ellipsisBefore = i === 2 && page > 3;
                    const ellipsisAfter  = i === totalPages - 3 && page < totalPages - 4;
                    if (!show) {
                      if (ellipsisBefore || ellipsisAfter)
                        return <span key={`e${i}`} className="text-[10px] text-gray-400 px-1">…</span>;
                      return null;
                    }
                    return (
                      <button key={i} onClick={() => setPage(i)}
                        className={cn(
                          "w-7 h-7 rounded-lg text-[10px] font-bold transition-all border",
                          page === i
                            ? "bg-orange-500 text-white border-orange-500 shadow-sm"
                            : "bg-white text-gray-600 border-gray-200 hover:bg-orange-50 hover:border-orange-200 hover:text-orange-600"
                        )}>
                        {i + 1}
                      </button>
                    );
                  })}
                </div>

                {/* Next */}
                <button onClick={() => setPage(p => Math.min(totalPages - 1, p + 1))} disabled={page === totalPages - 1}
                  className="flex items-center gap-1 px-3 py-1.5 text-[10px] font-semibold rounded-xl border border-gray-200 bg-white text-gray-600 hover:bg-gray-50 disabled:opacity-40 disabled:cursor-not-allowed transition-all">
                  Next →
                </button>
              </div>
            </div>
          )}
        </div>

        {/* Detail panel */}
        {detailFinding && (
          <FindingDetailPanel
            finding={detailFinding}
            onClose={() => setDetailId(null)}
            onRefresh={load}
            canEdit={can("update_finding")}
          />
        )}
      </div>
    </div>
  );
}
